

/* === LAB 핵심 로직 === */
const GRID=28;
const canvas=document.getElementById('canvas');
const introModal=document.getElementById('introModal');
const introClose=document.getElementById('introClose');
let mode='medium',medium=null,era=null,preset=null;
let blocks=[];
let dragEl=null,dragOx=0,dragOy=0;
let compareOn=false;
let activeBlock=null; 
let currentScale=1; 
let guideCloseTimer=null;
let currentGuideState=null;
let guideTransitionTimer=null;

function closeIntroModal(){
  if(!introModal) return;
  if(guideCloseTimer){
    clearTimeout(guideCloseTimer);
    guideCloseTimer=null;
  }
  if(guideTransitionTimer){
    clearTimeout(guideTransitionTimer);
    guideTransitionTimer=null;
  }
  introModal.classList.add('hide');
  const guideOpenBtn=document.getElementById('guideOpenBtn');
  if(guideOpenBtn) guideOpenBtn.classList.remove('on');
  document.querySelectorAll('.guide-target').forEach(el=>el.classList.remove('guide-target'));
}

function openIntroGuide(){
  if(!introModal) return;
  if(guideCloseTimer){
    clearTimeout(guideCloseTimer);
    guideCloseTimer=null;
  }
  introModal.classList.remove('hide');
  const guideOpenBtn=document.getElementById('guideOpenBtn');
  if(guideOpenBtn) guideOpenBtn.classList.add('on');
  currentGuideState=null;
  updateIntroGuide();
}

if(introClose){
  introClose.addEventListener('click', closeIntroModal);
}

document.addEventListener('keydown', (e) => {
  if(e.key === 'Escape' && introModal && !introModal.classList.contains('hide')){
    closeIntroModal();
  }
});

const GUIDE_TARGETS={
  medium:()=>document.getElementById('mediumChoiceGroup'),
  era:()=>document.getElementById('eraChoiceGroup'),
  layout:()=>document.getElementById('presetGrid'),
  box:()=>document.querySelector('.box-palette-item')
};

const GUIDE_STEPS={
  medium:{index:1,title:'매체 선택',copy:'오른쪽 패널에서 원하는 매체를 먼저 고르세요.'},
  era:{index:2,title:'시대 선택',copy:'선택한 매체에 맞는 시대를 고르세요.'},
  layout:{index:3,title:'레이아웃 선택',copy:'레이아웃 번호를 눌러 예시를 불러오세요.'},
  box:{index:4,title:'상자 배치',copy:'오른쪽 박스를 종이 위로 끌어 놓아보세요.'},
  done:{index:4,title:'좋아요, 준비됐습니다',copy:'이제 이 앱을 자유롭게 즐겨보세요.'}
};

function getGuideStep(){
  if(!medium) return 'medium';
  if(!era) return 'era';
  if(preset===null) return 'layout';
  const hasPlacedBox=blocks.some(b=>b.dataset && b.dataset.type==='original-box');
  if(!hasPlacedBox) return 'box';
  return 'done';
}

function updateIntroGuide(){
  if(!introModal || introModal.classList.contains('hide')) return;
  const state=getGuideStep();
  const order=['medium','era','layout','box'];
  const activeIndex=order.indexOf(state);
  const stepData=GUIDE_STEPS[state]||GUIDE_STEPS.medium;
  const kicker=document.getElementById('introKicker');
  const title=document.getElementById('introTitle');
  const copy=document.getElementById('introCopy');
  const content=document.getElementById('introContent');

  const applyStepContent=()=>{
    if(kicker) kicker.textContent=state==='done'?'Complete':`Step ${stepData.index} / 4`;
    if(title) title.textContent=stepData.title;
    if(copy) copy.textContent=stepData.copy;
  };

  if(currentGuideState && currentGuideState!==state && content){
    if(guideTransitionTimer) clearTimeout(guideTransitionTimer);
    content.classList.add('step-changing');
    guideTransitionTimer=setTimeout(()=>{
      applyStepContent();
      content.classList.remove('step-changing');
      guideTransitionTimer=null;
    },120);
  } else {
    applyStepContent();
    if(content) content.classList.remove('step-changing');
  }
  currentGuideState=state;

  document.querySelectorAll('[data-guide-dot]').forEach(dot=>{
    const step=dot.dataset.guideDot;
    const stepIndex=order.indexOf(step);
    dot.classList.toggle('active',step===state);
    dot.classList.toggle('complete',state==='done'||(activeIndex>-1&&stepIndex<activeIndex));
  });

  document.querySelectorAll('.guide-target').forEach(el=>el.classList.remove('guide-target'));
  if(state==='done'){
    if(!guideCloseTimer){
      guideCloseTimer=setTimeout(closeIntroModal,2200);
    }
    return;
  }
  if(guideCloseTimer){
    clearTimeout(guideCloseTimer);
    guideCloseTimer=null;
  }

  const targetFactory=GUIDE_TARGETS[state];
  const target=targetFactory && targetFactory();
  if(target) target.classList.add('guide-target');
}

