/* === 블록 조작 및 마우스 이벤트 === */
canvas.addEventListener('mousedown', e => {
  if(e.target === canvas || e.target.classList.contains('overlay-master')){
    clearActiveBlock();
  }
});

function clearActiveBlock(){
  if(activeBlock) activeBlock.classList.remove('selected');
  activeBlock = null;
}

function setActiveBlock(el){
  if(activeBlock) activeBlock.classList.remove('selected');
  activeBlock = el;
  if(el) el.classList.add('selected');
}

function deleteActiveBlock(){
  if(!activeBlock) return;
  activeBlock.remove();
  blocks = blocks.filter(b => b !== activeBlock);
  clearActiveBlock();
  updateBoxPaletteUsage();
}

