/* 매체 모드용 모눈종이 그리드 (5px 간격, 20% 불투명도) */
const MEDIUM_GRID_SIZE = 3; // px 간격 (더 촘촘하게)

function addMediumGrid(){
  const old = canvas.querySelector('.medium-grid-overlay');
  if(old) old.remove();
  const cw = parseFloat(canvas.style.width) || canvas.offsetWidth;
  const ch = parseFloat(canvas.style.height) || canvas.offsetHeight;
  if(!cw || !ch) return;

  const svg = document.createElementNS('http://www.w3.org/2000/svg','svg');
  svg.setAttribute('width','100%');
  svg.setAttribute('height','100%');
  svg.style.cssText = 'position:absolute;left:0;top:0;pointer-events:none;z-index:2;opacity:0.2;';
  svg.classList.add('medium-grid-overlay');

  let lines = '';
  const step = MEDIUM_GRID_SIZE;
  for(let x = step; x < cw; x += step){
    lines += `<line x1="${x}" y1="0" x2="${x}" y2="${ch}" stroke="#000" stroke-width="0.5"/>`;
  }
  for(let y = step; y < ch; y += step){
    lines += `<line x1="0" y1="${y}" x2="${cw}" y2="${y}" stroke="#000" stroke-width="0.5"/>`;
  }
  svg.innerHTML = lines;
  canvas.appendChild(svg);
}

function addFixedGraphicHints(layoutId){
  const old=canvas.querySelector('.fixed-graphic-hints');
  if(old) old.remove();
  if(!layoutId) return;

  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  if(!cw||!ch) return;

  const svg=document.createElementNS('http://www.w3.org/2000/svg','svg');
  svg.setAttribute('width','100%');
  svg.setAttribute('height','100%');
  svg.setAttribute('viewBox',`0 0 ${cw} ${ch}`);
  svg.classList.add('fixed-graphic-hints');

  const rect=(x,y,w,h,fill='#111',opacity='0.82')=>{
    const r=document.createElementNS('http://www.w3.org/2000/svg','rect');
    r.setAttribute('x',x*cw);
    r.setAttribute('y',y*ch);
    r.setAttribute('width',w*cw);
    r.setAttribute('height',h*ch);
    r.setAttribute('fill',fill);
    r.setAttribute('opacity',opacity);
    svg.appendChild(r);
  };
  const line=(x1,y1,x2,y2,color='#c8001e',width=2)=>{
    const l=document.createElementNS('http://www.w3.org/2000/svg','line');
    l.setAttribute('x1',x1*cw);
    l.setAttribute('y1',y1*ch);
    l.setAttribute('x2',x2*cw);
    l.setAttribute('y2',y2*ch);
    l.setAttribute('stroke',color);
    l.setAttribute('stroke-width',width);
    l.setAttribute('opacity','0.68');
    svg.appendChild(l);
  };

  if(layoutId==='dnt'&&medium==='ad'&&era==='neue'&&preset===0){
    rect(0.6306,0.0562,0.3097,0.0116);
    rect(0.6097,0.7151,0.0208,0.0591);
    rect(0.9069,0.9448,0.0208,0.0068);
    const arrow=document.createElementNS('http://www.w3.org/2000/svg','polygon');
    arrow.setAttribute('points',[
      `${0.929*cw},${0.937*ch}`,
      `${0.963*cw},${0.948*ch}`,
      `${0.929*cw},${0.959*ch}`
    ].join(' '));
    arrow.setAttribute('fill','#111');
    arrow.setAttribute('opacity','0.82');
    svg.appendChild(arrow);
  }

  if(layoutId==='utopolis'&&medium==='book'&&era==='neue'&&preset===0){
    line(0.1143,0,0.1143,1,'#c8001e',2);
    line(0,0.6552,0.1152,0.6552,'#c8001e',2);
    line(0.7054,0.1392,0.965,0.1392,'#c8001e',2);

    const g=document.createElementNS('http://www.w3.org/2000/svg','g');
    g.setAttribute('opacity','0.76');
    const px=0.0375*cw, py=0.7227*ch, pw=0.0464*cw, ph=0.158*ch;
    const add=(node)=>g.appendChild(node);
    const ellipse=document.createElementNS('http://www.w3.org/2000/svg','ellipse');
    ellipse.setAttribute('cx',px+pw*0.5);
    ellipse.setAttribute('cy',py+ph*0.12);
    ellipse.setAttribute('rx',pw*0.18);
    ellipse.setAttribute('ry',ph*0.09);
    ellipse.setAttribute('fill','#111');
    add(ellipse);
    const body=document.createElementNS('http://www.w3.org/2000/svg','path');
    body.setAttribute('d',`M ${px+pw*.28} ${py+ph*.24} L ${px+pw*.72} ${py+ph*.24} L ${px+pw*.82} ${py+ph*.7} L ${px+pw*.6} ${py+ph*.7} L ${px+pw*.6} ${py+ph*.96} L ${px+pw*.4} ${py+ph*.96} L ${px+pw*.4} ${py+ph*.7} L ${px+pw*.18} ${py+ph*.7} Z`);
    body.setAttribute('fill','#111');
    add(body);
    const book=document.createElementNS('http://www.w3.org/2000/svg','rect');
    book.setAttribute('x',px+pw*.33);
    book.setAttribute('y',py+ph*.36);
    book.setAttribute('width',pw*.34);
    book.setAttribute('height',ph*.22);
    book.setAttribute('fill','#f5f5f0');
    book.setAttribute('opacity','0.9');
    add(book);
    const base=document.createElementNS('http://www.w3.org/2000/svg','ellipse');
    base.setAttribute('cx',px+pw*.5);
    base.setAttribute('cy',py+ph*.98);
    base.setAttribute('rx',pw*.5);
    base.setAttribute('ry',ph*.12);
    base.setAttribute('fill','#111');
    add(base);
    svg.appendChild(g);
  }

  if(svg.childNodes.length) canvas.appendChild(svg);
}

/* 매체 모드 모눈 스냅
   - 좌상단(left/top)을 항상 가장 가까운 모눈 칸 경계에 정확히 맞춘다.
   - 결과적으로 박스는 한 칸(5px) 단위로 딱딱 끊겨서 이동하며,
     칸 사이에 어중간하게 걸치는 일이 없다. */
function snapToMediumGrid(x, y, w, h){
  const step = MEDIUM_GRID_SIZE;
  const cw = parseFloat(canvas.style.width) || canvas.offsetWidth;
  const ch = parseFloat(canvas.style.height) || canvas.offsetHeight;

  // 가장 가까운 모눈 칸으로 반올림 → 한 칸 단위 이동
  let sx = Math.round(x / step) * step;
  let sy = Math.round(y / step) * step;

  return {
    x: Math.max(0, Math.min(cw - w, sx)),
    y: Math.max(0, Math.min(ch - h, sy))
  };
}

function selectMedium(med,btn){
  medium=med;era=null;preset=null;
  document.querySelectorAll('.medium-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('expandSection').classList.add('open');
  document.getElementById('eraClassic').classList.remove('active');
  document.getElementById('eraNeue').classList.remove('active');
  updateEraButtons();
  document.getElementById('presetGrid').innerHTML='';
  clearOverlay();
  currentBoxes=null; currentOverlaySrc=null;
  setReferencePreview(null);
  canvas.innerHTML='';blocks=[];clearActiveBlock();
  setCanvasSize(420,560);
  addMediumGrid();
  renderBoxPalette();
  updateIntroGuide();
}

function updateEraButtons(){
  const classicBtn=document.getElementById('eraClassic');
  if(!classicBtn) return;
  classicBtn.style.display=(medium==='poster'||medium==='ad')?'none':'';
}

function selectEra(e){
  if(e==='classic' && (medium==='poster'||medium==='ad')) return;
  era=e;
  ['eraClassic','eraNeue'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.classList.remove('active');
  });
  if(e==='classic'){ document.getElementById('eraClassic').classList.add('active'); } 
  else { document.getElementById('eraNeue').classList.add('active'); }
  renderPresets();
  updateIntroGuide();
}

function renderPresets(){
  const grid=document.getElementById('presetGrid');
  if(!grid) return;
  grid.innerHTML='';
  if(!medium||!era) return;
  const list=(PRESETS[medium]||{})[era]||[];
  list.forEach((p,i)=>{
    const btn=document.createElement('button');
    btn.type='button';
    btn.className='preset-btn'+(preset===i?' active':'');
    btn.textContent=String(i+1);
    btn.onclick=()=>loadPreset(i);
    grid.appendChild(btn);
  });
}

function setReferencePreview(src,label){
  const preview=document.getElementById('referencePreview');
  const img=document.getElementById('referencePreviewImg');
  const caption=document.getElementById('referencePreviewLabel');
  if(!preview||!img) return;

  if(!src){
    preview.classList.add('hide');
    img.removeAttribute('src');
    if(caption) caption.textContent='원본 참고';
    return;
  }

  img.src=src;
  if(caption) caption.textContent=label||'원본 참고';
  preview.classList.remove('hide');
}

function loadPreset(idx){
  preset=idx;
  document.querySelectorAll('.preset-btn').forEach((b,i)=>b.classList.toggle('active',i===idx));

  // 레이아웃을 바꿀 때마다 '원본 비교'는 꺼진 상태로 초기화
  clearOverlay();
  canvas.innerHTML=''; blocks=[]; clearActiveBlock();

  const layoutId = getLayoutId(medium, era, idx);

  if(!layoutId){
    // 빈 레이아웃: 기본 세로 대지 + 모눈 그리드만 (오버레이/박스 없음)
    currentBoxes = null;
    currentOverlaySrc = null;
    setReferencePreview(null);
    setCanvasSize(420,560);
    addMediumGrid();
    renderBoxPalette();           // 안내 문구만 표시
    updateIntroGuide();
    return;
  }

  const def = LAYOUT_DEFS[layoutId];
  currentBoxes = def.boxes;
  currentOverlaySrc = def.img;
  setReferencePreview(def.img,`${medium} · ${era} · layout ${idx+1}`);
  setCanvasSize(def.cw, def.ch);  // 대지를 이미지 비율에 맞춤 (수정사항 1·3)
  addMediumGrid();
  addFixedGraphicHints(layoutId);
  addPresetImageBlocks(def);
  addImageOverlay(def.img);       // 원본 비교 이미지 (compareOn 상태에 따라 표시)
  renderBoxPalette();             // 아직 안 올린 박스만 팔레트에 표시
  updateIntroGuide();
}

/* ─── 1. 원본 비교 오버레이: PDF 사각형 좌표 기반 SVG 오버레이 ─── */
