// (매체, 시대, 레이아웃번호) → 레이아웃 id (null = 빈 대지)
function getLayoutId(med, e, idx){
  if(med==='poster' && e==='neue'){
    if(idx===0) return 'frauPoster';
    if(idx===1) return 'entfesseltePoster';
  }
  if(med==='book' && e==='classic' && idx===0) return 'penguinBook';
  if(med==='book' && e==='neue'){
    if(idx===0) return 'utopolis';                        // 책·신타이포·레이아웃1 = utopolis
    if(idx===1) return 'typoMitteilungen';
  }
  if(med==='ad' && e==='neue'){
    if(idx===0) return 'dnt';
    if(idx===1) return 'werbefoto';
  }
  if(e==='classic' && idx===0) return 'dnt';              // 고전·레이아웃1 = Die Neue Typographie
  return null;
}

// 현재 레이아웃 상태
let currentBoxes = null;       // [{x,y,w,h,name}] (이미지 기준 비율) 또는 null
let currentOverlaySrc = null;  // 원본 비교용 이미지 src 또는 null

function setCanvasSize(w,h){
  canvas.style.width  = w + 'px';
  canvas.style.height = h + 'px';
  resetZoomForMediumMode();
}

function addImageOverlay(src){
  let ov=document.getElementById('masterOverlay'); if(ov) ov.remove();
  let darkOv=document.getElementById('darkOverlay'); if(darkOv) darkOv.remove();

  const wrapper = document.createElement('div');
  wrapper.id = 'masterOverlay';
  wrapper.className = 'overlay-master';
  wrapper.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:3;opacity:0;transition:opacity 0.5s ease;';

  const img = document.createElement('img');
  img.src = src;
  // 대지 비율 = 이미지 비율 이므로 object-fit:fill 로 채워도 왜곡 없이 박스와 1:1 정렬
  img.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;object-fit:fill;opacity:0.35;display:block;';
  wrapper.appendChild(img);
  if(compareOn) wrapper.style.opacity = '1';
  canvas.appendChild(wrapper);
}

function addOverlayImage(){
  let ov=document.getElementById('masterOverlay');if(ov)ov.remove();

  const wrapper = document.createElement('div');
  wrapper.id = 'masterOverlay';
  wrapper.className = 'overlay-master';
  wrapper.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:3;opacity:0;transition:opacity 0.5s ease;';

  const img = document.createElement('img');
  img.src = WERBEFOTO_IMG;
  img.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:0.35;display:block;';
  wrapper.appendChild(img);
  if(compareOn) wrapper.style.opacity = '1';
  canvas.appendChild(wrapper);
}

function clearOverlay(){
  const ov=document.getElementById('masterOverlay');
  if(ov) ov.remove();
  const darkOv=document.getElementById('darkOverlay');
  if(darkOv) darkOv.remove();
  compareOn=false;
  const btn=document.getElementById('compareBtn');
  if(btn){
    btn.classList.remove('on');
    btn.textContent='원본 비교';
  }
}

function toggleCompare(){
  if(!currentOverlaySrc && !document.getElementById('masterOverlay')) return;  // 빈 레이아웃은 무시
  if(currentOverlaySrc && !document.getElementById('masterOverlay')){
    addImageOverlay(currentOverlaySrc);
  }
  compareOn=!compareOn;
  const ov=document.getElementById('masterOverlay');
  if(ov){
    ov.style.opacity = compareOn ? '1' : '0';
  }
  const btn=document.getElementById('compareBtn');
  if(btn){
    btn.classList.toggle('on',compareOn);
    btn.textContent=compareOn?'비교 끄기':'원본 비교';
  }
}

/* ─── 2/3. 캔버스 줌(휠) + 패닝(드래그) ─── */
const canvasWrap = document.getElementById('canvasWrap');

// 줌 상태
let zoomScale = 1;        // 현재 줌 배율 (기준 100% = fit-to-view 배율)
let baseFitScale = 1;     // 처음 fit 시의 scale (이게 100%)
let panX = 0, panY = 0;   // 패닝 오프셋 (px)
let isPanning = false;
let panStartX = 0, panStartY = 0;
let panStartPanX = 0, panStartPanY = 0;
let isOverCanvas = false;

// 대지의 transform-origin을 center center로 고정
canvas.style.transformOrigin = 'center center';

function applyCanvasTransform(){
  const totalScale = baseFitScale * zoomScale;
  canvas.style.transform = `translate(${panX}px, ${panY}px) scale(${totalScale})`;
  currentScale = totalScale;
  updateZoomDisplay();
}

function updateZoomDisplay(){
  const pct = Math.round(zoomScale * 100);
  const el = document.getElementById('zoomValue');
  if(el) el.textContent = pct + '%';
}

function setZoomLevel(pct){
  zoomScale = pct / 100;
  applyCanvasTransform();
}

// 줌 레벨 초기화 (fit-to-view 기준으로 baseFitScale 설정)
function initFitScale(){
  const cw = parseFloat(canvas.style.width) || canvas.offsetWidth;
  const ch = parseFloat(canvas.style.height) || canvas.offsetHeight;
  if(!cw || !ch) return;
  const wrapW = canvasWrap.clientWidth - 120;
  const wrapH = canvasWrap.clientHeight - 120;
  const sx = wrapW / cw;
  const sy = wrapH / ch;
  baseFitScale = Math.min(sx, sy, 1.2);
  zoomScale = 1;
  panX = 0;
  panY = 0;
  applyCanvasTransform();
}

// 매체모드 100% 기준: 대지(420×560)가 화면을 거의 꽉 채우는 배율
function resetZoomForMediumMode(){
  const ww = canvasWrap.clientWidth;
  const wh = canvasWrap.clientHeight;
  const cw = parseFloat(canvas.style.width) || 420;
  const ch = parseFloat(canvas.style.height) || 560;
  if(ww && wh){
    // 100% = 대지가 캔버스 영역을 거의 꽉 채우는 fit 배율 (92% 여백)
    baseFitScale = Math.min(ww / cw, wh / ch) * 0.92;
  } else {
    baseFitScale = 1;
  }
  zoomScale = 1;
  panX = 0;
  panY = 0;
  canvas.style.transformOrigin = 'center center';
  applyCanvasTransform();
}

// 휠 줌
canvasWrap.addEventListener('wheel', e => {
  e.preventDefault();
  const factor = Math.exp(-e.deltaY * 0.001);
  zoomScale = Math.max(0.1, Math.min(10, zoomScale * factor));
  applyCanvasTransform();
}, { passive: false });

// 패닝: canvasWrap 위에서 캔버스가 아닌 빈 영역 드래그, 또는 Space+드래그
let spaceDown = false;
document.addEventListener('keydown', ev => { if(ev.code === 'Space' && !ev.target.isContentEditable) spaceDown = true; });
document.addEventListener('keyup', ev => { if(ev.code === 'Space') spaceDown = false; });

canvasWrap.addEventListener('mousedown', e => {
  // 빈 배경 클릭 또는 스페이스바+드래그
  const onCanvas = canvas.contains(e.target) && e.target !== canvas;
  if(!onCanvas || spaceDown){
    isPanning = true;
    panStartX = e.clientX;
    panStartY = e.clientY;
    panStartPanX = panX;
    panStartPanY = panY;
    canvasWrap.style.cursor = 'grabbing';
    e.preventDefault();
  }
});

document.addEventListener('mousemove', e => {
  if(!isPanning) return;
  panX = panStartPanX + (e.clientX - panStartX);
  panY = panStartPanY + (e.clientY - panStartY);
  applyCanvasTransform();
});

document.addEventListener('mouseup', () => {
  if(isPanning){
    isPanning = false;
    canvasWrap.style.cursor = '';
  }
});

/* ─── 4. 줌 UI 박스 (좌하단) ─── */
// HTML에서 렌더링되므로 JS에서는 함수만 제공
function zoomStep(direction){
  const steps = [25, 50, 75, 100, 200, 300, 400, 500];
  const cur = Math.round(zoomScale * 100);
  if(direction === 'up'){
    const next = steps.find(s => s > cur);
    if(next) setZoomLevel(next);
  } else {
    const prev = [...steps].reverse().find(s => s < cur);
    if(prev) setZoomLevel(prev);
  }
}

function applyZoomInput(){
  const el = document.getElementById('zoomValue');
  if(!el) return;
  
  el.contentEditable = "false";
  const text = el.textContent.trim();
  let val = parseInt(text);
  
  if(isNaN(val) || val <= 0){
    val = Math.round(zoomScale * 100);
  } else {
    if(val < 25) val = 25;
    if(val > 500) val = 500;
  }
  
  setZoomLevel(val);
}

/* 줌 드롭다운 토글 */
function toggleZoomDropdown(){
  const dd = document.getElementById('zoomDropdown');
  if(!dd) return;
  dd.style.display = dd.style.display === 'block' ? 'none' : 'block';
}

document.addEventListener('click', e => {
  const dd = document.getElementById('zoomDropdown');
  const box = document.getElementById('zoomBox');
  if(dd && box && !box.contains(e.target)){
    dd.style.display = 'none';
  }
});

function selectZoomPreset(pct){
  setZoomLevel(pct);
  const dd = document.getElementById('zoomDropdown');
  if(dd) dd.style.display = 'none';
}



const BOX_NAMES=["헤더","그래픽 요소 1","출판 정보","저자 정보","메인 타이틀","본문","각주 1","각주 2","그래픽 요소 2","각주 3"];
function renderBoxPalette(){
  const c=document.getElementById('sliderContainer');
  if(!c) return;
  c.innerHTML='';

  if(!currentBoxes){
    c.innerHTML='<div style="font-size:11px;color:#ccc;letter-spacing:2px;text-transform:uppercase;font-family:\'Arial Narrow\',Arial,sans-serif">레이아웃을 선택하세요</div>';
    return;
  }

  // 이미 종이에 올라간 박스 인덱스
  const used = new Set(
    blocks.filter(b=>b.dataset && b.dataset.type==='original-box')
          .map(b=>b.dataset.boxIndex)
  );

  const hint=document.createElement('div');
  hint.className='box-palette-hint';
  hint.textContent='박스를 종이 위로 드래그';
  c.appendChild(hint);

  const palette=document.createElement('div');
  palette.className='box-palette-grid';

  let remaining=0;
  currentBoxes.forEach((box,i)=>{
    if((box.kind||'text')==='image') return;
    if(used.has(String(i))) return;        // [수정사항 4] 사용한 박스는 팔레트에서 제외
    remaining++;
    const ratio=box.w/box.h;
    const maxW=72, maxH=44;
    let pw=maxW, ph=pw/ratio;
    if(ph>maxH){ ph=maxH; pw=ph*ratio; }

    const item=document.createElement('div');
    const kind=box.kind||'text';
    item.className='box-palette-item '+(kind==='image'?'image-box-item':'text-box-item');
    item.draggable=true;
    item.dataset.boxIndex=String(i);
    item.dataset.kind=kind;

    const shape=document.createElement('div');
    shape.className='box-palette-shape '+(kind==='image'?'image-shape':'text-shape');
    shape.style.width=pw+'px';
    shape.style.height=ph+'px';

    const label=document.createElement('span');
    label.textContent=(box.name||('박스 '+(i+1)))+' · '+(kind==='image'?'이미지':'텍스트');

    item.appendChild(shape);
    item.appendChild(label);
    item.addEventListener('dragstart',e=>{
      e.dataTransfer.setData('text/plain',String(i));
      e.dataTransfer.effectAllowed='copy';
    });
    item.addEventListener('dragend',()=>canvas.classList.remove('drop-ready'));
    palette.appendChild(item);
  });

  c.appendChild(palette);

  if(remaining===0){
    const done=document.createElement('div');
    done.style.cssText='font-size:11px;color:#999;letter-spacing:2px;text-transform:uppercase;font-family:\'Arial Narrow\',Arial,sans-serif;margin-top:6px;';
    done.textContent='모든 박스를 배치했습니다';
    c.appendChild(done);
  }
}

function addPresetImageBlocks(def){
  if(!def || !Array.isArray(def.boxes)) return;
  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;

  def.boxes.forEach((box,i)=>{
    if((box.kind||'text')!=='image') return;

    const el=document.createElement('div');
    el.className='block original-box-block image-box-block fixed-image-block';
    el.style.left=Math.round(box.x*cw)+'px';
    el.style.top=Math.round(box.y*ch)+'px';
    el.style.width=Math.round(box.w*cw)+'px';
    el.style.height=Math.round(box.h*ch)+'px';
    el.textContent=box.name||('이미지 '+(i+1));
    el.dataset.type='fixed-image';
    el.dataset.boxIndex=String(i);
    el.dataset.kind='image';
    canvas.appendChild(el);
  });
}

function getOriginalOverlayMetrics(){
  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  // PDF 실제 비율: 595.2760 / 841.8900
  const imageRatio=595.2760/841.8900;
  const canvasRatio=cw/ch;
  let w=cw,h=ch,x=0,y=0;

  if(canvasRatio>imageRatio){
    // canvas가 더 넓음 → 좌우 letterbox
    h=ch;
    w=ch*imageRatio;
    x=(cw-w)/2;
    y=0;
  } else {
    // canvas가 더 좁음 → 상하 letterbox
    w=cw;
    h=cw/imageRatio;
    x=0;
    y=(ch-h)/2;
  }

  return {cw,ch,x,y,w,h};
}

function getLayoutOneGridMetrics(){
  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  // xRatios/yRatios가 이미 canvas 기준 비율이므로 cw/ch 직접 곱셈
  const xR=LAYOUT1_GRID.xRatios;
  const yR=LAYOUT1_GRID.yRatios;
  const left   = xR[0]*cw;
  const col1End= xR[1]*cw;
  const col2Sta= xR[2]*cw;
  const right  = xR[3]*cw;
  const top    = yR[0]*ch;
  const bottom = yR[yR.length-1]*ch;
  const width  = right-left;
  const height = bottom-top;
  const col1W  = col1End-left;
  const gutter = col2Sta-col1End;
  const col2W  = right-col2Sta;
  return {cw,ch,x:0,y:0,w:cw,h:ch,
          left,top,width,height,col1W,gutter,col2W,
          col1End,col2Sta};
}

function addLayoutOneGrid(){
  const old=canvas.querySelector('.layout-one-grid');
  if(old) old.remove();

  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  const g=getLayoutOneGridMetrics();

  const grid=document.createElement('div');
  grid.className='layout-one-grid';
  grid.style.cssText='position:absolute;left:0;top:0;pointer-events:none;z-index:2;';
  grid.style.width=cw+'px';
  grid.style.height=ch+'px';

  // 수직 라인: xRatios의 4개 경계선
  LAYOUT1_GRID.xRatios.forEach(xr=>{
    const xPos=xr*cw;
    const line=document.createElement('div');
    line.className='layout-one-grid-line vertical';
    line.style.cssText=`position:absolute;left:${xPos}px;top:${g.top}px;width:1px;height:${g.height}px;background:rgba(120,120,120,.25);`;
    grid.appendChild(line);
  });

  // 수평 라인: yRatios의 모든 경계선
  LAYOUT1_GRID.yRatios.forEach(yr=>{
    const yPos=yr*ch;
    const line=document.createElement('div');
    line.className='layout-one-grid-line horizontal';
    line.style.cssText=`position:absolute;top:${yPos}px;left:${g.left}px;height:1px;width:${g.width}px;background:rgba(120,120,120,.25);`;
    grid.appendChild(line);
  });

  canvas.appendChild(grid);
}

/* ─── 레이아웃 2 전용: PDF 좌표 기반 그리드/박스/스냅 ─── */
function isLayoutTwo(){ return era==='neue' && preset===1; }

function addLayoutTwoGrid(){
  const old=canvas.querySelector('.layout-one-grid');
  if(old) old.remove();

  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  const xs=LAYOUT2_GRID.xRatios.map(r=>r*cw);
  const ys=LAYOUT2_GRID.yRatios.map(r=>r*ch);

  const grid=document.createElement('div');
  grid.className='layout-one-grid';
  grid.style.cssText='position:absolute;left:0;top:0;pointer-events:none;z-index:2;';
  grid.style.width=cw+'px';
  grid.style.height=ch+'px';

  // 수직(열) 라인 — 대지 위/아래 끝까지 (여백 없음)
  xs.forEach(xPos=>{
    const line=document.createElement('div');
    line.className='layout-one-grid-line vertical';
    line.style.cssText=`position:absolute;left:${xPos}px;top:0px;width:1px;height:${ch}px;background:rgba(120,120,120,.45);`;
    grid.appendChild(line);
  });
  // 수평(단) 라인 — 대지 좌/우 끝까지 (여백 없음)
  ys.forEach(yPos=>{
    const line=document.createElement('div');
    line.className='layout-one-grid-line horizontal';
    line.style.cssText=`position:absolute;top:${yPos}px;left:0px;height:1px;width:${cw}px;background:rgba(120,120,120,.45);`;
    grid.appendChild(line);
  });

  canvas.appendChild(grid);
}

function snapLayoutTwoPosition(x,y,w,h){
  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  const xStops=LAYOUT2_GRID.xRatios.map(r=>r*cw);
  const yStops=LAYOUT2_GRID.yRatios.map(r=>r*ch);
  const SNAP_DIST = 8;

  let bestX = x;
  let minDX = SNAP_DIST;
  xStops.forEach(stop => {
    if(Math.abs(stop - x) < minDX){ minDX = Math.abs(stop - x); bestX = stop; }
    if(Math.abs(stop - (x+w)) < minDX){ minDX = Math.abs(stop - (x+w)); bestX = stop - w; }
  });

  let bestY = y;
  let minDY = SNAP_DIST;
  yStops.forEach(stop => {
    if(Math.abs(stop - y) < minDY){ minDY = Math.abs(stop - y); bestY = stop; }
    if(Math.abs(stop - (y+h)) < minDY){ minDY = Math.abs(stop - (y+h)); bestY = stop - h; }
  });

  return {
    x:Math.max(0,Math.min(cw-w,bestX)),
    y:Math.max(0,Math.min(ch-h,bestY))
  };
}

function renderLayoutTwoBoxButtons(){ renderBoxPalette(); }

function createLayoutTwoBoxBlock(idx,clientX,clientY){ createBoxBlock(idx,clientX,clientY); }

function snapLayoutOnePosition(x,y,w,h){
  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  const SNAP_DIST = 8; // 스냅 거리 (px)

  const xStops=LAYOUT1_GRID.xRatios.map(r=>r*cw);
  const yStops=LAYOUT1_GRID.yRatios.map(r=>r*ch);

  // x 방향: left edge 또는 right edge(x+w)가 xStop에 스냅
  let bestX = x;
  let minDX = SNAP_DIST;
  xStops.forEach(stop => {
    // left edge snap
    if(Math.abs(stop - x) < minDX){ minDX = Math.abs(stop - x); bestX = stop; }
    // right edge snap
    if(Math.abs(stop - (x+w)) < minDX){ minDX = Math.abs(stop - (x+w)); bestX = stop - w; }
  });

  // y 방향: top edge 또는 bottom edge(y+h)가 yStop에 스냅
  let bestY = y;
  let minDY = SNAP_DIST;
  yStops.forEach(stop => {
    // top edge snap
    if(Math.abs(stop - y) < minDY){ minDY = Math.abs(stop - y); bestY = stop; }
    // bottom edge snap
    if(Math.abs(stop - (y+h)) < minDY){ minDY = Math.abs(stop - (y+h)); bestY = stop - h; }
  });

  return {
    x:Math.max(0,Math.min(cw-w,bestX)),
    y:Math.max(0,Math.min(ch-h,bestY))
  };
}

function createBoxBlock(idx,clientX,clientY){
  if(!currentBoxes) return;
  const box=currentBoxes[idx];
  if(!box) return;

  const cw=parseFloat(canvas.style.width)||canvas.offsetWidth;
  const ch=parseFloat(canvas.style.height)||canvas.offsetHeight;
  const bw=Math.round(box.w*cw);
  const bh=Math.round(box.h*ch);
  let x=Math.round(box.x*cw);
  let y=Math.round(box.y*ch);

  if(typeof clientX==='number'&&typeof clientY==='number'){
    const cr=canvas.getBoundingClientRect();
    x=Math.round((clientX-cr.left)/currentScale-bw/2);
    y=Math.round((clientY-cr.top)/currentScale-bh/2);
  }

  x=Math.max(0,Math.min(cw-bw,x));
  y=Math.max(0,Math.min(ch-bh,y));
  const snapped=snapToMediumGrid(x,y,bw,bh);
  x=Math.round(snapped.x);
  y=Math.round(snapped.y);

  const kind=box.kind||'text';
  const el=document.createElement('div');
  el.className='block original-box-block '+(kind==='image'?'image-box-block':'text-box-block');
  el.style.left=x+'px';
  el.style.top=y+'px';
  el.style.width=bw+'px';
  el.style.height=bh+'px';
  el.textContent=box.name||('박스 '+(idx+1));
  el.dataset.type='original-box';
  el.dataset.boxIndex=String(idx);
  el.dataset.kind=kind;
  el.dataset.baseW=String(bw);
  el.dataset.baseH=String(bh);
  el.dataset.scale='1';
  makeDraggable(el);
  canvas.appendChild(el);
  blocks.push(el);
  setActiveBlock(el);
  renderBoxPalette();   // [수정사항 4] 방금 올린 박스를 팔레트에서 제거
  updateIntroGuide();
}

canvas.addEventListener('dragover',e=>{
  if(currentBoxes && e.dataTransfer.types.includes('text/plain')){
    e.preventDefault();
    canvas.classList.add('drop-ready');
  }
});

canvas.addEventListener('dragleave',e=>{
  if(!canvas.contains(e.relatedTarget)) canvas.classList.remove('drop-ready');
});

canvas.addEventListener('drop',e=>{
  if(!currentBoxes) return;
  canvas.classList.remove('drop-ready');
  const raw=e.dataTransfer.getData('text/plain');
  if(raw==='') return;
  const idx=parseInt(raw,10);
  if(Number.isNaN(idx)) return;
  e.preventDefault();
  createBoxBlock(idx,e.clientX,e.clientY);
});

function makeDraggable(el){
  el.addEventListener('mousedown',e=>{
    if(spaceDown) return; // 스페이스 패닝 중엔 블록 드래그 안함
    if(!e.target.hasAttribute('contenteditable')){
      e.preventDefault();
    }
    dragEl=el;
    setActiveBlock(el);
    const r=el.getBoundingClientRect();
    
    // 확대/축소된 배율을 역산하여 드래그 오프셋 계산 (중요)
    dragOx=(e.clientX-r.left)/currentScale; 
    dragOy=(e.clientY-r.top)/currentScale;
    el.classList.add('dragging');
  });
}
document.addEventListener('mousemove',e=>{
  if(!dragEl) return;
  const cr=canvas.getBoundingClientRect();
  
  let unscaledX = (e.clientX - cr.left) / currentScale;
  let unscaledY = (e.clientY - cr.top) / currentScale;
  
  let targetX = unscaledX - dragOx;
  let targetY = unscaledY - dragOy;

  let w = parseFloat(canvas.style.width);
  let h = parseFloat(canvas.style.height);

  let x = Math.max(0, Math.min(w - dragEl.offsetWidth, targetX));
  let y = Math.max(0, Math.min(h - dragEl.offsetHeight, targetY));
  if(mode==='medium'){
    // 모든 박스가 모눈 한 칸 단위로 걸리도록 스냅
    const snapped=snapToMediumGrid(x,y,dragEl.offsetWidth,dragEl.offsetHeight);
    x=snapped.x;
    y=snapped.y;
  }
  
  dragEl.style.left=x+'px';
  dragEl.style.top=y+'px';
});
document.addEventListener('mouseup',()=>{if(dragEl){dragEl.classList.remove('dragging');dragEl=null;}});

function renderSliders(blks){
  const c=document.getElementById('sliderContainer');c.innerHTML='';
  const imgs=blks.filter(b=>b.dataset.type==='img');
  if(!imgs.length){
    c.innerHTML='<div style="font-size:11px;color:#ccc;letter-spacing:2px;text-transform:uppercase;font-family:Arial Narrow,Arial,sans-serif">레이아웃을 선택하세요</div>';
    return;
  }
  imgs.forEach((el,i)=>{
    const row=document.createElement('div');row.className='scale-row';
    const top=document.createElement('div');top.className='scale-row-top';
    const lbl=document.createElement('label');lbl.textContent='도판 '+(i+1);
    const val=document.createElement('span');val.className='scale-val';val.textContent='50%';
    const sl=document.createElement('input');sl.type='range';sl.min='20';sl.max='150';sl.value='50';sl.step='5';
    sl.oninput=()=>{
      const s=sl.value/100;
      val.textContent=sl.value+'%';
      el.style.width=Math.round(parseInt(el.dataset.baseW)*s)+'px';
      el.style.height=Math.round(parseInt(el.dataset.baseH)*s)+'px';
    };
    top.appendChild(lbl);top.appendChild(val);
    row.appendChild(top);row.appendChild(sl);
    c.appendChild(row);
  });
}



function downloadCanvas(){
  const canvasElement = document.getElementById('canvas');
  if (!canvasElement) return;

  // 1. 기존 transform 스타일 백업
  const originalTransform = canvasElement.style.transform;
  
  // 2. 캡처를 위해 임시로 transform 리셋
  canvasElement.style.transform = 'none';

  // 3. html2canvas 로딩 확인
  if (typeof html2canvas === 'undefined') {
    alert('이미지 저장 라이브러리(html2canvas)를 불러오는 중입니다. 잠시 후 다시 시도해 주세요.');
    canvasElement.style.transform = originalTransform; // 복원
    return;
  }

  // 4. 캡처 실행
  html2canvas(canvasElement, {
    scale: 2, // 2배 고해상도
    useCORS: true, // CORS 이미지 허용
    backgroundColor: '#ffffff', // 배경을 흰색으로 지정
    logging: false
  }).then(canvas => {
    // 5. 다운로드 처리
    const link = document.createElement('a');
    link.download = 'tschichold-layout.png';
    link.href = canvas.toDataURL('image/png');
    link.click();
    
    // 6. transform 복원
    canvasElement.style.transform = originalTransform;
  }).catch(err => {
    console.error('이미지 저장 실패:', err);
    alert('이미지 저장 중 오류가 발생했습니다.');
    // 7. 오류 시에도 복원
    canvasElement.style.transform = originalTransform;
  });
}

document.addEventListener('keydown', (e) => {
  const tag = document.activeElement?.tagName;

  if (
    tag === 'INPUT' ||
    tag === 'TEXTAREA' ||
    document.activeElement?.isContentEditable
  ) {
    return;
  }

  if ((e.key === 'Backspace' || e.key === 'Delete') && activeBlock) {
    e.preventDefault();
    deleteActiveBlock();
  }
});

// 줌 수치 수동 입력 바인딩 초기화
(function initZoomInputInteraction() {
  const el = document.getElementById('zoomValue');
  if (!el) return;

  el.contentEditable = "false";

  el.addEventListener('dblclick', function() {
    this.contentEditable = "true";
    let currentText = this.textContent.trim();
    if (currentText.endsWith('%')) {
      this.textContent = currentText.slice(0, -1);
    }
    this.focus();
    
    const range = document.createRange();
    range.selectNodeContents(this);
    const sel = window.getSelection();
    sel.removeAllRanges();
    sel.addRange(range);
  });

  el.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      e.preventDefault();
      this.blur();
    }
  });

  el.addEventListener('blur', function() {
    applyZoomInput();
  });
})();

